changeSet.sql:
ALTER TABLE file_metadata ENABLE ROW LEVEL SECURITY;
ALTER TABLE file_metadata FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON file_metadata
    USING (tenant_id = current_setting('app.current_tenant_id', true)::uuid);
GRANT SELECT, INSERT, UPDATE, DELETE ON file_metadata TO file_service;

rollback.sql:
DROP POLICY IF EXISTS tenant_isolation ON file_metadata;
ALTER TABLE file_metadata NO FORCE ROW LEVEL SECURITY;
ALTER TABLE file_metadata DISABLE ROW LEVEL SECURITY;
